// UploadBills.jsx — FINAL ANDROID UI VERSION (no UI change removed, only styling added)

import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const API = process.env.REACT_APP_API_BASE;

export default function UploadBills({ employee }) {
  const navigate = useNavigate();
  const [files, setFiles] = useState(null);
  const [bills, setBills] = useState([]);

  // Fetch existing bills
  useEffect(() => {
    if (!employee?.empld) return;

    axios
      .get(`${API}/bills/${employee.empld}`)
      .then((res) => setBills(res.data.bills || []))
      .catch(() => setBills([]));
  }, [employee]);

  // Upload bills
  const handleUpload = async () => {
    if (!files) return alert("Please select a file");

    const formData = new FormData();
    for (let f of files) formData.append("bills", f);

    formData.append("empId", employee.empld);

    await axios.post(`${API}/bills/upload`, formData);
    window.location.reload();
  };

  // Delete bill
  const deleteBill = async (id) => {
    await axios.delete(`${API}/bills/delete/${id}`);
    setBills((prev) => prev.filter((b) => b.id !== id));
  };

  const green = "#0f9d58";
  const light = "#e8f7ee";

  return (
    <div
      style={{
        background: light,
        minHeight: "100vh",
        padding: "25px",
        display: "flex",
        justifyContent: "center",
      }}
    >

      {/* MAIN CARD */}
      <div
        style={{
          width: "90%",
          maxWidth: "750px",
          background: "#fff",
          padding: "22px",
          borderRadius: "18px",
          boxShadow: "0px 4px 12px rgba(0,0,0,0.1)",
        }}
      >
        {/* HEADER */}
        <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
          <button
            onClick={() => navigate(-1)}
            style={{
              background: light,
              border: "none",
              padding: "10px 14px",
              borderRadius: "12px",
              fontSize: "18px",
              cursor: "pointer",
            }}
          >
            ←
          </button>

          <h2 style={{ color: green, margin: 0 }}>Upload Bills</h2>
        </div>

        <p style={{ marginTop: "10px", color: "#555" }}>
          Employee: {employee?.name} • {employee?.empld}
        </p>

        {/* UPLOAD AREA */}
        <div
          style={{
            background: light,
            padding: "18px",
            borderRadius: "14px",
            marginTop: "18px",
          }}
        >
          <label style={{ fontWeight: "600", fontSize: "15px" }}>
            Choose Bills
          </label>

          <div style={{ display: "flex", gap: "10px", marginTop: "10px" }}>
            <input
              type="file"
              multiple
              onChange={(e) => setFiles(e.target.files)}
              style={{
                flex: 1,
                padding: "10px",
                borderRadius: "10px",
              }}
            />

            <button
              onClick={handleUpload}
              style={{
                background: green,
                color: "white",
                border: "none",
                padding: "10px 20px",
                borderRadius: "10px",
                cursor: "pointer",
              }}
            >
              Upload
            </button>
          </div>
        </div>

        {/* TABLE */}
        <table style={{ width: "100%", marginTop: "25px" }}>
          <thead>
            <tr>
              <th style={{ padding: "10px", background: light }}>Date</th>
              <th style={{ padding: "10px", background: light }}>File Name</th>
              <th style={{ padding: "10px", background: light }}>Preview</th>
              <th style={{ padding: "10px", background: light }}>Delete</th>
            </tr>
          </thead>

          <tbody>
            {bills.length === 0 ? (
              <tr>
                <td colSpan="4" style={{ textAlign: "center", padding: "20px" }}>
                  No bills uploaded
                </td>
              </tr>
            ) : (
              bills.map((bill) => (
                <tr key={bill.id}>
                  <td style={{ padding: "10px" }}>
                    {bill.uploaded_at?.split("T")[0]}
                  </td>
                  <td style={{ padding: "10px" }}>{bill.file_name}</td>

                  <td style={{ padding: "10px" }}>
                    <a
                      href={`${API}/${bill.file_path}`}
                      target="_blank"
                      rel="noreferrer"
                      style={{
                        background: green,
                        color: "#fff",
                        padding: "6px 12px",
                        borderRadius: "8px",
                        textDecoration: "none",
                      }}
                    >
                      View
                    </a>
                  </td>

                  <td style={{ padding: "10px" }}>
                    <button
                      onClick={() => deleteBill(bill.id)}
                      style={{
                        background: "#d9534f",
                        color: "white",
                        padding: "6px 12px",
                        borderRadius: "8px",
                        border: "none",
                        cursor: "pointer",
                      }}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>

      </div>
    </div>
  );
}
